#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXM 100005

// Structure to represent an edge
typedef struct Edge {
    int to;
    int label;
    struct Edge* next;
} Edge;

// Structure to represent a graph
typedef struct Graph {
    int numVertices;
    int numEdges;
    Edge** adjList;
} Graph;

// Function to create a new edge
Edge* createEdge(int to, int label) {
    Edge* edge = (Edge*) malloc(sizeof(Edge));
    edge->to = to;
    edge->label = label;
    edge->next = NULL;
    return edge;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int from, int to, int label) {
    Edge* edge = createEdge(to, label);
    edge->next = graph->adjList[from];
    graph->adjList[from] = edge;
}

// Function to perform topological sort
void topologicalSort(Graph* graph, int* sequence) {
    int* inDegree = (int*) malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        inDegree[i] = 0;
    }
    for (int i = 0; i < graph->numVertices; i++) {
        Edge* edge = graph->adjList[i];
        while (edge != NULL) {
            inDegree[edge->to]++;
            edge = edge->next;
        }
    }
    int* queue = (int*) malloc(graph->numVertices * sizeof(int));
    int front = 0, rear = 0;
    for (int i = 0; i < graph->numVertices; i++) {
        if (inDegree[i] == 0) {
            queue[rear++] = i;
        }
    }
    int index = 0;
    while (front < rear) {
        int vertex = queue[front++];
        sequence[index++] = vertex;
        Edge* edge = graph->adjList[vertex];
        while (edge != NULL) {
            inDegree[edge->to]--;
            if (inDegree[edge->to] == 0) {
                queue[rear++] = edge->to;
            }
            edge = edge->next;
        }
    }
    free(inDegree);
    free(queue);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        Graph* graph = (Graph*) malloc(sizeof(Graph));
        graph->numVertices = N + 1;
        graph->numEdges = M;
        graph->adjList = (Edge**) malloc((N + 1) * sizeof(Edge*));
        for (int i = 0; i <= N; i++) {
            graph->adjList[i] = NULL;
        }
        for (int i = 0; i < M; i++) {
            int from, to;
            scanf("%d %d", &from, &to);
            addEdge(graph, from, to, 1);
        }
        int* sequence = (int*) malloc(N * sizeof(int));
        topologicalSort(graph, sequence);
        for (int i = 0; i < N; i++) {
            printf("%d ", sequence[i] + 1);
        }
        printf("\n");
        free(sequence);
        for (int i = 0; i <= N; i++) {
            Edge* edge = graph->adjList[i];
            while (edge != NULL) {
                Edge* temp = edge;
                edge = edge->next;
                free(temp);
            }
        }
        free(graph->adjList);
        free(graph);
    }
    return 0;

