#include <queue>
using namespace std;

// Structure to represent an edge
struct Edge {
    int to;
    int label;
};

// Structure to represent a graph
struct Graph {
    int numVertices;
    int numEdges;
    vector<vector<Edge>> adjList;
};

// Function to add an edge to the graph
void addEdge(Graph& graph, int from, int to, int label) {
    Edge edge;
    edge.to = to;
    edge.label = label;
    graph.adjList[from].push_back(edge);
}

// Function to perform topological sort
void topologicalSort(Graph& graph, vector<int>& sequence) {
    vector<int> inDegree(graph.numVertices, 0);
    for (int i = 0; i < graph.numVertices; i++) {
        for (Edge edge : graph.adjList[i]) {
            inDegree[edge.to]++;
        }
    }
    queue<int> q;
    for (int i = 0; i < graph.numVertices; i++) {
        if (inDegree[i] == 0) {
            q.push(i);
        }
    }
    int index = 0;
    while (!q.empty()) {
        int vertex = q.front();
        q.pop();
        sequence[index++] = vertex;
        for (Edge edge : graph.adjList[vertex]) {
            inDegree[edge.to]--;
            if (inDegree[edge.to] == 0) {
                q.push(edge.to);
            }
        }
    }
}

