import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;
public class Main {
    // Structure to represent an edge
    static class Edge {
        int to;
        int label;
        Edge(int to, int label) {
            this.to = to;
            this.label = label;
        }
    }
    // Structure to represent a graph
    static class Graph {
        int numVertices;
        int numEdges;
        Edge[][] adjList;
        Graph(int numVertices, int numEdges) {
            this.numVertices = numVertices;
            this.numEdges = numEdges;
            adjList = new Edge[numVertices][];
        }
    }
    // Function to add an edge to the graph
    static void addEdge(Graph graph, int from, int to, int label) {
        Edge edge = new Edge(to, label);
        if (graph.adjList[from] == null) {
            graph.adjList[from] = new Edge[1];
            graph.adjList[from][0] = edge;
        } else {
            Edge[] temp = new Edge[graph.adjList[from].length + 1];
            System.arraycopy(graph.adjList[from], 0, temp, 0, graph.adjList[from].length);
            temp[temp.length - 1] = edge;
            graph.adjList[from] = temp;
        }
    }
    // Function to perform topological sort
    static void topologicalSort(Graph graph, int[] sequence) {
        int[] inDegree = new int[graph.numVertices];
        for (int i = 0; i < graph.numVertices; i++) {
            if (graph.adjList[i] != null) {
                for (Edge edge : graph.adjList[i]) {
                    inDegree[edge.to]++;
                }
            }
        }
        Queue<Integer> q = new LinkedList<>();
        for (int i = 0; i < graph.numVertices; i++) {
            if (inDegree[i] == 0) {
                q.add(i);
            }
        }
        int index = 0;
        while (!q.isEmpty()) {
            int vertex = q.poll();
            sequence[index++] = vertex;
            if (graph.adjList[vertex] != null) {
                for (Edge edge : graph.adjList[vertex]) {
                    inDegree[edge.to]--;
                    if (inDegree[edge.to] == 0) {
                        q.add(edge.to);
                    }
                }
            }
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            Graph graph = new Graph(N + 1, M);
            for (int i = 0; i < M; i++) {
                int from = sc.nextInt();
                int to = sc.nextInt();
                addEdge(graph, from, to, 1);
            }
            int[] sequence = new int[N];
            topologicalSort(graph, sequence);
            for (int i = 0; i < N; i++) {
                System.out.print(sequence[i] + 1 + " ");
            }
            System.out.println();
        }
    }
}

