class Graph:
    def __init__(self, numVertices, numEdges):
        self.numVertices = numVertices
        self.numEdges = numEdges
        self.adjList = [[] for _ in range(numVertices)]

# Function to add an edge to the graph
def addEdge(graph, fromVertex, toVertex, label):
    edge = Edge(toVertex, label)
    graph.adjList[fromVertex].append(edge)

# Function to perform topological sort
def topologicalSort(graph, sequence):
    inDegree = [0] * graph.numVertices
    for i in range(graph.numVertices):
        for edge in graph.adjList[i]:
            inDegree[edge.to] += 1
    q = deque()
    for i in range(graph.numVertices):
        if inDegree[i] == 0:
            q.append(i)
    index = 0
    while q:
        vertex = q.popleft()
        sequence[index] = vertex
        index += 1
        for edge in graph.adjList[vertex]:
            inDegree[edge.to] -= 1
            if inDegree[edge.to] == 0:
                q.append(edge.to)

